import { Injectable, inject, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, tap } from 'rxjs';
import { API_BASE } from '../api';
import { Cart } from '../models';

@Injectable({ providedIn: 'root' })
export class CartService {
  private readonly http = inject(HttpClient);

  private _cart = signal<Cart | null>(null);
  readonly cart = this._cart.asReadonly();
  readonly itemCount = computed(() =>
    (this._cart()?.items ?? []).reduce((sum, i) => sum + i.quantity, 0),
  );

  load(): Observable<Cart> {
    return this.http
      .get<Cart>(`${API_BASE}/cart`)
      .pipe(tap((cart) => this._cart.set(cart)));
  }

  addItem(productId: string, quantity: number): Observable<Cart> {
    return this.http
      .post<Cart>(`${API_BASE}/cart/items`, { productId, quantity })
      .pipe(tap((cart) => this._cart.set(cart)));
  }

  updateItem(itemId: string, quantity: number): Observable<Cart> {
    return this.http
      .patch<Cart>(`${API_BASE}/cart/items/${itemId}`, { quantity })
      .pipe(tap((cart) => this._cart.set(cart)));
  }

  removeItem(itemId: string): Observable<Cart> {
    return this.http
      .delete<Cart>(`${API_BASE}/cart/items/${itemId}`)
      .pipe(tap((cart) => this._cart.set(cart)));
  }

  clearLocal(): void {
    this._cart.set(null);
  }
}
